1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const PROCESSING_FEE = 5;
11	const INITIAL_ASSESSMENT_MULTIPLIER = 1.1;
12	const SUBSEQUENT_CONTRACT_MULTIPLIER = 0.85;
13	const ALIKE_BUNDLE_DISCOUNT = 15;
14	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
15	const HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER = 1.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
18	const LOYALTY_THRESHOLD = 2;
19	const COMPONENT_TYPES = ["rune", "moonstone"];
20	
21	type Item = { type: string; cursed?: boolean; enchantment?: number };
22	
23	function ceilToWholeGold(amount: number): number {
24	  return Math.ceil(Math.round(amount * 1e6) / 1e6);
25	}
26	
27	function basePremiumFor(itemType: string): number {
28	  return BASE_PREMIUMS[itemType] ?? 0;
29	}
30	
31	function isHighlyEnchanted(item: Item): boolean {
32	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
33	}
34	
35	function itemPremium(item: Item): number {
36	  const base = basePremiumFor(item.type);
37	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE_MULTIPLIER : 1;
38	  const enchantmentMultiplier = isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER : 1;
39	  return base * cursedMultiplier * enchantmentMultiplier;
40	}
41	
42	function countOfType(items: Array<Item>, itemType: string): number {
43	  return items.filter((item) => item.type === itemType).length;
44	}
45	
46	function alikeBundleDiscount(items: Array<Item>): number {
47	  const bundleCount = COMPONENT_TYPES.reduce(
48	    (sum, componentType) => sum + Math.floor(countOfType(items, componentType) / 3),
49	    0,
50	  );
51	  return bundleCount * ALIKE_BUNDLE_DISCOUNT;
52	}
53	
54	function contractHistoryMultiplierFor(previousQuotes: number): number {
55	  return previousQuotes >= 1 ? SUBSEQUENT_CONTRACT_MULTIPLIER : INITIAL_ASSESSMENT_MULTIPLIER;
56	}
57	
58	function loyaltyMultiplierFor(yearsWithMHPCO: number): number {
59	  return yearsWithMHPCO >= LOYALTY_THRESHOLD ? LOYALTY_DISCOUNT_MULTIPLIER : 1;
60	}
61	
62	export function quote(input: { items: Array<Item>; previousQuotes?: number; yearsWithMHPCO?: number }): number {
63	  const itemPremiumSum = input.items.reduce((sum, item) => sum + itemPremium(item), 0);
64	  const itemsTotal = itemPremiumSum - alikeBundleDiscount(input.items);
65	  const contractHistoryMultiplier = contractHistoryMultiplierFor(input.previousQuotes ?? 0);
66	  const loyaltyMultiplier = loyaltyMultiplierFor(input.yearsWithMHPCO ?? 0);
67	  const total = itemsTotal * contractHistoryMultiplier * loyaltyMultiplier + PROCESSING_FEE;
68	  return ceilToWholeGold(total);
69	}
70	
71	export function claim(_input: unknown): number {
72	  return undefined as unknown as number;
73	}
